        const visibleTop = (0 - panOffset.y) / zoomLevel;
        const visibleWidth = containerWidth / zoomLevel;
        const visibleHeight = containerHeight / zoomLevel;
        
        const rectX = currentMinimapDx + visibleLeft * currentMinimapScale;
